export { ScrollArea } from "./scroll-area";
export type {
  ScrollAreaOrientation,
  ScrollAreaPadding,
  ScrollAreaProps,
  ScrollAreaSize,
} from "./scroll-area";

.mrg-scroll-area {
  --mrg-scroll-area-max-block-size: 24rem;
  --mrg-scroll-area-padding: var(--mrg-semantic-space-inline-sm);
  box-sizing: border-box;
  background: var(--mrg-semantic-color-background-canvas);
  border-block: var(--mrg-semantic-border-width-default) solid
    var(--mrg-semantic-color-border-default);
  max-block-size: var(--mrg-scroll-area-max-block-size);
  min-block-size: 0;
  min-inline-size: 0;
  overflow: auto;
  overflow-wrap: anywhere;
  overscroll-behavior: auto;
  scrollbar-color: var(--mrg-semantic-color-brand-living)
    var(--mrg-semantic-color-background-surface-sunken);
  scrollbar-gutter: stable;
  scrollbar-width: auto;
  scroll-padding-block: var(--mrg-scroll-area-padding);
  scroll-padding-inline: var(--mrg-scroll-area-padding);
}

.mrg-scroll-area[data-size="sm"] {
  --mrg-scroll-area-max-block-size: 12rem;
}

.mrg-scroll-area[data-size="lg"] {
  --mrg-scroll-area-max-block-size: 36rem;
}

.mrg-scroll-area[data-size="viewport"] {
  --mrg-scroll-area-max-block-size: calc(
    100dvb - env(safe-area-inset-top, 0px) - env(safe-area-inset-bottom, 0px) -
      (2 * var(--mrg-semantic-space-page))
  );
}

.mrg-scroll-area[data-scroll-padding="none"] {
  --mrg-scroll-area-padding: 0px;
}

.mrg-scroll-area[data-scroll-padding="md"] {
  --mrg-scroll-area-padding: var(--mrg-semantic-space-inline-md);
}

.mrg-scroll-area[data-contain-overscroll="true"] {
  overscroll-behavior: contain;
}

.mrg-scroll-area[data-orientation="horizontal"] {
  max-block-size: none;
  white-space: nowrap;
}

.mrg-scroll-area:focus-visible {
  box-shadow: 0 0 0 var(--mrg-component-focus-indicator-offset)
    var(--mrg-component-focus-indicator-contrast-background);
  outline: var(--mrg-component-focus-indicator-width) solid
    var(--mrg-component-focus-indicator-color);
  outline-offset: var(--mrg-component-focus-indicator-offset);
}

.mrg-scroll-area::-webkit-scrollbar {
  block-size: var(--mrg-semantic-size-target-minimum);
  inline-size: var(--mrg-semantic-size-target-minimum);
}

.mrg-scroll-area::-webkit-scrollbar-track {
  background: var(--mrg-semantic-color-background-surface-sunken);
}

.mrg-scroll-area::-webkit-scrollbar-thumb {
  background: var(--mrg-semantic-color-brand-living);
  background-clip: content-box;
  border: var(--mrg-semantic-border-width-strong) solid transparent;
  border-radius: var(--mrg-semantic-radius-pill);
}

@media (forced-colors: active) {
  .mrg-scroll-area {
    border-block-color: CanvasText;
    scrollbar-color: auto;
  }

  .mrg-scroll-area:focus-visible {
    box-shadow: none;
    outline-color: Highlight;
  }
}

import { forwardRef, type HTMLAttributes } from "react";

import "./scroll-area.css";

export type ScrollAreaOrientation = "vertical" | "horizontal" | "both";
export type ScrollAreaSize = "sm" | "md" | "lg" | "viewport";
export type ScrollAreaPadding = "none" | "sm" | "md";

type AccessibleName =
  | {
      /** Supplies an optional direct region name and is excluded when focusable is false. */
      readonly "aria-label": string;
      /** References an optional region name and is excluded when focusable is false. */
      readonly "aria-labelledby"?: string;
    }
  | {
      /** Supplies an optional direct region name and is excluded when focusable is false. */
      readonly "aria-label"?: string;
      /** References an optional region name and is excluded when focusable is false. */
      readonly "aria-labelledby": string;
    };

interface ScrollAreaBaseProps extends Omit<
  HTMLAttributes<HTMLDivElement>,
  "aria-label" | "aria-labelledby" | "role" | "tabIndex"
> {
  /** Chooses the intended native scroll direction without replacing browser scrolling. */
  readonly orientation?: ScrollAreaOrientation;
  /** A semantic maximum block size; viewport also accounts for physical safe-area insets. */
  readonly size?: ScrollAreaSize;
  /** Keeps focused descendants clear of the scrollport edge and sticky content. */
  readonly scrollPadding?: ScrollAreaPadding;
  /** Contains scroll chaining at the region boundary. */
  readonly containOverscroll?: boolean;
}

export type ScrollAreaProps = ScrollAreaBaseProps &
  (
    | ({
        /** Controls opt-in region focus; true requires a name and false removes region semantics. */
        readonly focusable: true;
      } & AccessibleName)
    | {
        /** Controls opt-in region focus; true requires a name and false removes region semantics. */
        readonly focusable?: false;
        /** Supplies an optional direct region name and is excluded when focusable is false. */
        readonly "aria-label"?: never;
        /** References an optional region name and is excluded when focusable is false. */
        readonly "aria-labelledby"?: never;
      }
  );

function joinScrollAreaClassName(className: string | undefined): string {
  return className === undefined || className.trim().length === 0
    ? "mrg-scroll-area"
    : `mrg-scroll-area ${className}`;
}

export const ScrollArea = forwardRef<HTMLDivElement, ScrollAreaProps>(function ScrollArea(
  {
    "aria-label": ariaLabel,
    "aria-labelledby": ariaLabelledBy,
    children,
    className,
    containOverscroll = false,
    focusable = false,
    orientation = "vertical",
    scrollPadding = "sm",
    size = "md",
    ...nativeProps
  },
  forwardedRef,
) {
  return (
    <div
      {...nativeProps}
      ref={forwardedRef}
      aria-label={focusable ? ariaLabel : undefined}
      aria-labelledby={focusable ? ariaLabelledBy : undefined}
      className={joinScrollAreaClassName(className)}
      data-contain-overscroll={containOverscroll ? "true" : "false"}
      data-focusable={focusable ? "true" : "false"}
      data-orientation={orientation}
      data-scroll-padding={scrollPadding}
      data-size={size}
      data-slot="scroll-area"
      role={focusable ? "region" : undefined}
      tabIndex={focusable ? 0 : undefined}
    >
      {children}
    </div>
  );
});

ScrollArea.displayName = "ScrollArea";
